/**
  The Atomic Signal Selector Engine.

  Enabled via `resetContext({ atomicSelectors: true })`. Replaces the reselect-backed
  `selectors()` builder with a leaf-level dependency tracking engine: every selector's
  compute function runs against tracking proxies that record exactly which leaf paths
  (object props, Map keys, Set membership, Array indices) were read. On the next read,
  a selector only recomputes if one of those exact leaves changed - not merely because
  its parent reducer object got a new reference.
*/

type SubPath =
  | { type: 'whole' }
  | { type: 'full' }
  | { type: 'prop'; prop: string }
  | { type: 'map'; key: any }
  | { type: 'set'; key: any }
  | { type: 'index'; index: number }

interface ArgMeta {
  kind: 'selector' | 'reducer'
  name: string
}

interface DepDescriptor {
  argIndex: number
  kind: 'selector' | 'reducer'
  name: string
  sub: SubPath
  value: any
  depPath: string
  causeLabel: string
}

interface AtomicNode {
  id: string
  name: string
  compute: (...args: any[]) => any
  argFns: Selector[]
  argMeta: ArgMeta[]
  hasRun: boolean
  evaluations: number
  lastResult: any
  deps: DepDescriptor[]
  dirtyCause: string | null
}

interface AtomicRegistry {
  nodes: Record<string, AtomicNode>
  order: string[]
}

function getRegistry(logic: Logic): AtomicRegistry {
  if (!logic.cache.atomic) {
    logic.cache.atomic = { nodes: {}, order: [] } as AtomicRegistry
  }
  return logic.cache.atomic as AtomicRegistry
}

