  const selectorInputs = typeof input === 'function' ? input(logic) : input
  const registry = getRegistry(logic)

  const keys = Object.keys(selectorInputs)

  for (const key of keys) {
    if (typeof logic.selectors[key] !== 'undefined') {
      throw new Error(`[KEA] Logic "${logic.pathString}" selector "${key}" already exists`)
    }
  }

  // pass 1: create nodes and stable placeholder selectors, so that siblings (even
  // defined later in the same object) can reference each other by identity.
  for (const key of keys) {
    const node: AtomicNode = {
      id: `${logic.pathString}::${key}`,
      name: key,
      compute: undefined as any,
      argFns: [],
      argMeta: [],
      hasRun: false,
      evaluations: 0,
      lastResult: undefined,
      deps: [],
      dirtyCause: null,
